    function test_approveToZeroAddress() public {
        token.approve(address(0), 100);
        assertEq(token.allowance(address(this), address(0)), 100);
    }

    // === COVERAGE TESTS (coverage_analyzer) ===

    // coverage: onlyOwner modifier happy path
    function test_OwnerCanMint() public {
        address recipient = address(0xBEEF);
        vm.prank(owner);
        token.mint(recipient, 100e18);
        assertEq(token.balanceOf(recipient), 100e18);
        assertEq(token.totalSupply(), INITIAL_SUPPLY + 100e18);
    }

