    function test_RevertWhen_TransferInsufficientBalance() public {
        address sender = address(0xCAFE);
        vm.prank(sender);
        vm.expectRevert("insufficient balance");
        token.transfer(owner, 1);
    }

    // coverage: approve happy path
    function test_Approve_Success() public {
        address spender = address(0xBEEF);
        vm.prank(owner);
        token.approve(spender, 100e18);
        assertEq(token.allowance(owner, spender), 100e18);
    }

    // coverage: transferFrom happy path
    function test_TransferFrom_Success() public {
        address from = owner;
        address to = address(0xBEEF);
        address spender = address(0xCAFE);
        vm.prank(from);
        token.approve(spender, 100e18);
        vm.prank(spender);
        token.transferFrom(from, to, 60e18);
        assertEq(token.balanceOf(to), 60e18);
        assertEq(token.balanceOf(from), INITIAL_SUPPLY - 60e18);
        assertEq(token.allowance(from, spender), 40e18);
    }

